windowclass.script:
local selected = false;
local readonly = false;
local fontvalue = "";
local selectedfont = "";
local framevalue = "";
local selectedframe = "";

function getFonts()
	return fontvalue,selectedfont;
end

function setFonts(normal,sel)
	fontvalue = normal or "";
	selectedfont = sel or "";
	setSelected(selected);
end

function getFrames()
	return framevalue,selectedframe;
end

function setFrames(normal,sel)
	framevalue = normal or "";
	selectedframe = sel or "";
	setSelected(selected);
end

function setReadOnly(flag)
	if flag then
	readonly = true;
	else
	readonly = false;
	end
end

function isReadOnly()
	return readonly;
end

function setSelected(flag)
	if flag then
		selected = true;
		setFrame(selectedframe);
	else
		selected = false;
		setFrame(framevalue);
	end
	if Text then
		if flag then
			Text.setFont(selectedfont);
		else
			Text.setFont(fontvalue);
		end
	end
end

function onInit()
	if selected then
		Text.setFont(selectedfont);
	else
		Text.setFont(fontvalue);
	end
end

function clicked()
	if windowlist and windowlist.optionClicked then
		windowlist.optionClicked(self);
	end
end

function isSelected()
	return selected;
end

function setRowHeight(h)
	local w,t = getSize();
	setSize(w,h);
end

function getRowHeight()
	local w,h = getSize();
	return h;
end

stringcontrol.script:
function onClickDown(...)
	return not window.isReadOnly();
end

function onClickRelease(...)
	window.clicked();
end

scrollbarcontrol.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	if target and target[1] then
		setTarget(target[1]);
	end
end
